import React, { useEffect } from 'react';
import { motion } from 'framer-motion';

export default function CurtainReveal({ isVisible, onAnimationComplete }) {
  useEffect(() => {
    if (isVisible) {
      console.log('CurtainReveal: Animation started');
      // Call completion callback after animation (1.5s)
      const timer = setTimeout(() => {
        console.log('CurtainReveal: Animation complete');
        onAnimationComplete?.();
      }, 1500);
      return () => clearTimeout(timer);
    }
  }, [isVisible, onAnimationComplete]);

  if (!isVisible) {
    console.log('CurtainReveal: Hidden');
    return null;
  }

  console.log('CurtainReveal: Rendering curtains');

  return (
    <>
      {/* LEFT CURTAIN */}
      <motion.div
        initial={{ x: 0 }}
        animate={{ x: "-100%" }}
        transition={{ duration: 1.5, ease: "easeInOut" }}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '50%',
          height: '100%',
          zIndex: 20,
          backgroundColor: 'rgba(26, 31, 58, 0.95)',
          backgroundImage: 'linear-gradient(90deg, rgba(26,31,58,0.95) 0%, rgba(26,31,58,0.5) 50%, transparent 100%)'
        }}
      />

      {/* RIGHT CURTAIN */}
      <motion.div
        initial={{ x: 0 }}
        animate={{ x: "100%" }}
        transition={{ duration: 1.5, ease: "easeInOut" }}
        style={{
          position: 'fixed',
          top: 0,
          right: 0,
          width: '50%',
          height: '100%',
          zIndex: 20,
          backgroundColor: 'rgba(26, 31, 58, 0.95)',
          backgroundImage: 'linear-gradient(270deg, rgba(26,31,58,0.95) 0%, rgba(26,31,58,0.5) 50%, transparent 100%)'
        }}
      />
    </>
  );
}
